const updateAccount = `-- name: UpdateAccount :one
UPDATE accounts SET
    display_name    = COALESCE($2, display_name),
    note            = COALESCE($3, note),
    avatar_media_id = COALESCE($4, avatar_media_id),
    header_media_id = COALESCE($5, header_media_id),
    bot             = COALESCE($6, bot),
    locked          = COALESCE($7, locked),
    fields          = COALESCE($8, fields),
    url             = COALESCE($9, url),
    updated_at      = NOW()
WHERE id = $1
RETURNING id, username, domain, display_name, note, public_key, private_key, inbox_url, outbox_url, followers_url, following_url, ap_id, bot, locked, suspended, silenced, created_at, updated_at, avatar_media_id, header_media_id, followers_count, following_count, statuses_count, fields, last_status_at, url
`

type UpdateAccountParams struct {
	ID            string  `json:"id"`
	DisplayName   *string `json:"display_name"`
	Note          *string `json:"note"`
	AvatarMediaID *string `json:"avatar_media_id"`
	HeaderMediaID *string `json:"header_media_id"`
	Bot           bool    `json:"bot"`
	Locked        bool    `json:"locked"`
	Fields        []byte  `json:"fields"`
	Url           *string `json:"url"`
}

func (q *Queries) UpdateAccount(ctx context.Context, arg UpdateAccountParams) (Account, error) {
	row := q.db.QueryRow(ctx, updateAccount,
		arg.ID,
		arg.DisplayName,
		arg.Note,
		arg.AvatarMediaID,
		arg.HeaderMediaID,
		arg.Bot,
		arg.Locked,
		arg.Fields,
		arg.Url,
	)
	var i Account
	err := row.Scan(
		&i.ID,
		&i.Username,
		&i.Domain,
		&i.DisplayName,
		&i.Note,
		&i.PublicKey,
		&i.PrivateKey,
		&i.InboxUrl,
		&i.OutboxUrl,
		&i.FollowersUrl,
		&i.FollowingUrl,
		&i.ApID,
		&i.Bot,
		&i.Locked,
		&i.Suspended,
		&i.Silenced,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.AvatarMediaID,
		&i.HeaderMediaID,
		&i.FollowersCount,
		&i.FollowingCount,
		&i.StatusesCount,
		&i.Fields,
		&i.LastStatusAt,
		&i.Url,
	)
	return i, err
}

